#include <bits/stdc++.h>
#define val first
#define idx second
using namespace std;

const int N=2e5+5;

int n,m,a[N],nxt[N],pre[N],ans;
bool del[N];
priority_queue<pair<int,int>> q;

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        nxt[i]=i%n+1;
        pre[i]=(i+n-2)%n+1;
        q.push(make_pair(a[i],i));
    }
    if(2*m>n){
        printf("Error!");
        return 0;
    }
    for(int i=1;i<=m;i++){
        while(del[q.top().idx])
            q.pop();
        pair<int,int> t=q.top();
        q.pop();
        ans+=t.val;
        int p=t.idx;
        a[p]=a[nxt[p]]+a[pre[p]]-a[p];
        del[nxt[p]]=del[pre[p]]=1;
        pre[p]=pre[pre[p]],nxt[p]=nxt[nxt[p]];
        nxt[pre[p]]=p,pre[nxt[p]]=p;
        q.push(make_pair(a[p],p));
    }
    printf("%d",ans);
    return 0;
}
